import { useState } from "react";
import css from "./Registration.module.css"
import { Button, Input } from "antd";
import { useNavigate } from "react-router-dom";

const Registration = () => {
    
    const navigate = useNavigate
    const [ NickName, setNickName ] = useState('');
    const [ ChatName, setChatName ] = useState('');

    const handleNickName = (e) => {
    setNickName(e.target.value);
    const NickName = setNickName(e.target.value)
};
    const handleChatName = (e) => {
    setChatName(e.target.value);
     const ChatName = setChatName(e.target.value)
    console.log('Текущее значение:', e.target.value);
};
    



    return (
        <>
            <div className={css.wrapper} >
                <div className={css.InputBlock}>

                    <label className={css.label}>Nickname</label>
                    <Input 
                    id="NickName" 
                    required 
                    type="text" 
                    placeholder="Enter nickname" 
                    className={css.NickName}
                    value={NickName}
                    onChange={handleNickName}
                    />
                    
                    <label className={css.label}>Chat name</label>
                    <Input 
                    id="ChatName" 
                    required 
                    type="text" 
                    placeholder="Enter the chat name" 
                    className={css.ChatName} 
                    value={ChatName}
                    onChange={handleChatName}
                    />
                    

                    <Button className={css.Button}>Войти</Button>
                </div>
            </div>
            <Button onClick={()=>navigate(`/${ChatName}`)} className={css.buttonAI}>Chat AI</Button>
        </>
    )
}

export default Registration;
